generated_oml:
// C3: Physical sensing components
instance MotorMountEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted rotary encoder measuring motor shaft position on the first axis"
    DTDFVocab:producedData MotorEncoderSignal
]

instance GearboxMountEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox‑mounted rotary encoder measuring joint (gearbox) shaft position on the first axis"
    DTDFVocab:producedData GearboxEncoderSignal
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor for the permanent‑magnet synchronous motor, measuring stator current"
    DTDFVocab:producedData MotorCurrentSignal
]

// C4: Physical-to-virtual interaction
instance MotorEncoderSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorMountEncoder
]

instance GearboxEncoderSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxMountEncoder
]

instance MotorCurrentSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C4: Additional simulated data transmission
instance SimulatedTorqueSignal : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SimulinkMotorModel
]

// C10: Models/Data - Simulation Models
instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "Simulink model of the permanent‑magnet synchronous motor for the first axis"
    DTDFVocab:inputTo SimulationEngine
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearwheel and cycloidal gearbox for the first axis"
    DTDFVocab:inputTo SimulationEngine
]

instance SimulinkFrictionModel : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Coulomb‑viscous, Stribeck, Dahl, and LuGre models for the first axis"
    DTDFVocab:inputTo SimulationEngine
]

instance SysMLAxisBlockDiagram : DTDFVocab:Model [
    base:desc "SysML block diagram of the first vertical axis (motor, gearwheel, cycloidal gearbox)"
]

// Service for simulation
instance SimulationService : DTDFVocab:Service [
    base:desc "Simulation service running Simulink models for motor, gearbox, and friction"
]

// C10: Models/Data - Simulated Data
instance SimulatedTorqueData : DTDFVocab:Data [
    base:desc "Simulated motor torque output from the Simulink motor model"
    DTDFVocab:fromData SimulatedTorqueSignal
    DTDFVocab:inputTo DataProcessingEngine
]

// C10: Models/Data - Sensor Data
instance MeasuredMotorAngleData : DTDFVocab:Data [
    base:desc "Measured motor shaft angle derived from the motor encoder"
    DTDFVocab:fromData MotorEncoderSignal
    DTDFVocab:inputTo DataProcessingEngine
]

instance MeasuredGearboxAngleData : DTDFVocab:Data [
    base:desc "Measured joint angle derived from the gearbox encoder"
    DTDFVocab:fromData GearboxEncoderSignal
    DTDFVocab:inputTo DataProcessingEngine
]

instance MeasuredCurrentData : DTDFVocab:Data [
    base:desc "Measured current from the motor current sensor"
    DTDFVocab:fromData MotorCurrentSignal
    DTDFVocab:inputTo DataProcessingEngine
]

// C11: Enablers
instance SimulationEngine : DTDFVocab:Enabler [
    base:desc "Execution component running Simulink simulation models for motor, gearbox, and friction"
    DTDFVocab:enables SimulationService
]

instance DataProcessingEngine : DTDFVocab:Enabler [
    base:desc "Processing component that executes data calculation models and the real‑time friction identification algorithm"
    DTDFVocab:enables FrictionIdentificationService, VisualizationDashboardService, ControllerTuningService
]

instance MQTTIngestionEngine : DTDFVocab:Enabler [
    base:desc "Component ingesting MQTT streams from encoder and current sensors into the digital twin"
    DTDFVocab:enables MQTTIngestionService
]

// C11: Services
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time friction identification service that produces analytical and data‑driven friction model parameters"
    DTDFVocab:provides FrictionParameterUpdateInsight, FrictionDriftDetectionInsight
]

instance VisualizationDashboardService : DTDFVocab:Service [
    base:desc "Dashboard service visualising measured versus simulated joint behaviour"
    DTDFVocab:provides RealTimeComparisonInsight
]

instance ControllerTuningService : DTDFVocab:Service [
    base:desc "Service providing controller tuning suggestions based on updated friction model parameters"
    DTDFVocab:provides ControllerTuningSuggestionInsight
]

instance MQTTIngestionService : DTDFVocab:Service [
    base:desc "Service handling MQTT ingestion of sensor data streams"
]

// C17: Insights
instance FrictionParameterUpdateInsight : DTDFVocab:Insight [
    base:desc "Updated friction model parameters derived from real‑time identification"
]

instance FrictionDriftDetectionInsight : DTDFVocab:Insight [
    base:desc "Detection of abnormal friction drift based on trend analysis of identification results"
]

instance RealTimeComparisonInsight : DTDFVocab:Insight [
    base:desc "Real‑time comparison of measured versus simulated joint behaviour displayed on the dashboard"
]

instance ControllerTuningSuggestionInsight : DTDFVocab:Insight [
    base:desc "Suggestion for controller parameter tuning derived from friction model updates"
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow is a unidirectional data consumer and does not send commands or actuation signals back to the robot."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Data ingestion and processing happens in real time during robot operation. Sensor samples are streamed continuously via MQTT while the simulation and model evaluation execute in near‑real‑time, synchronised with the robot’s control cycles."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The constellation is composed of the DT data ingestion layer (MQTT), a processing engine that runs the simulation and calculation models, a data store for the data traces, and a visualization dashboard. All components are orchestrated under the Digital Shadow Reference Model and driven by the Asset Administration Shell of the robot’s first axis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital twin covers the operated stage of the robot, i.e. it reflects the manufacturing and real‑world operation of the first axis while continually updating its models using live data."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Model fidelity relies on accurate analytic friction models and real‑time identification; validation is achieved by comparing simulated torque, angular velocity and acceleration against measured data traces. Uncertainties from wear, load changes and temperature are mitigated by continuous model updating and traceability through AAS and metadata."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol is used for streaming sensor data from the robot to the digital shadow; Asset Administration Shells are exposed over a compatible interface (e.g., REST/JSON) to share contextual information within the local network."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML (UML profile) for engineering models, Asset Administration Shells for data exchange, and MATLAB/Simulink for simulation – no explicit ISO/IEC 30141 mentioned."
]
